function addDifferentialPrivacyNoise(predictions, epsilon) {
    // Laplace noise for differential privacy
    const sensitivity = 1.0;
    const scale = sensitivity / epsilon;

    return predictions.map(p => {
        const u = Math.random() - 0.5;
        const laplace = -scale * Math.sign(u) * Math.log(1 - 2 * Math.abs(u));
        return Math.max(0, Math.min(1, p + laplace));
    });
}

function truncateToTopK(predictions, k, precision) {
    const indexed = predictions.map((p, i) => ({ prob: p, index: i }));
    indexed.sort((a, b) => b.prob - a.prob);

    const multiplier = Math.pow(10, precision);
    return indexed.slice(0, k).map(item => ({
        class: item.index,
        confidence: Math.round(item.prob * multiplier) / multiplier
    }));
}

