    const riskScore = this.calculateOverallRisk(risks);

    return { riskScore, risks, queryCount: queries.length };
  }

  calculateInputSpaceVariance(queries) {
    const inputs = queries.map(q => q.input).flat();
    const mean = inputs.reduce((a, b) => a + b, 0) / inputs.length;
    const variance = inputs.reduce((sum, x) => sum + Math.pow(x - mean, 2), 0) / inputs.length;
    return variance;
