    const inputs = queries.map(q => JSON.stringify(q.input));
    const uniqueInputs = new Set(inputs);
    return uniqueInputs.size / inputs.length;
  }

  calculateOverallRisk(risks) {
    const severityScores = { critical: 40, high: 25, medium: 15 };
    return Math.min(100, risks.reduce((sum, r) => sum + severityScores[r.severity], 0));
