    const uniqueValues = new Set(roundedInputs);

    // Grid search typically has few unique values repeated
    if (uniqueValues.size < inputData.length * 0.3) return 0.8;
    return uniqueValues.size / inputData.length;
  }

  detectBoundaryProbing(inputData) {
    // Check if inputs are clustered near decision boundaries
    const extremeCount = inputData.filter(x => Math.abs(x) > 0.9 || Math.abs(x) < 0.1).length;
    return extremeCount / inputData.length;
  }

  // Global rate limiting across all users
  async checkGlobalRateLimit() {
    const key = 'global:query_count';
    const count = await redis.incr(key);
    if (count === 1) {
      await redis.expire(key, 3600);
    }
    return count > GLOBAL_QUERY_LIMIT;
  }

  // Distributed rate limiting by user behavior cluster
  async checkBehaviorClusterLimit(userId, fingerprint) {
    const clusterKey = `cluster:${fingerprint.substring(0, 8)}`;
    const count = await redis.incr(clusterKey);
    if (count === 1) {
      await redis.expire(clusterKey, 3600);
    }
    // If many users are making similar queries, likely coordinated attack
    return count > 50;
  }
}

const defense = new ModelInversionDefense();

// Middleware for model inversion detection
async function modelInversionDetection(req, res, next) {
  const userId = req.user?.id || req.ip;
  const { inputData } = req.body;

  if (!inputData || !Array.isArray(inputData)) {
    return next();
  }

  const fingerprint = defense.computeQueryFingerprint(inputData);

  // Check global rate limit
  if (await defense.checkGlobalRateLimit()) {
    console.warn(JSON.stringify({
      event: 'global_rate_limit_exceeded',
      timestamp: new Date().toISOString()
    }));
    return res.status(503).json({ error: 'Service temporarily unavailable' });
  }

  // Check behavior cluster limit
  if (await defense.checkBehaviorClusterLimit(userId, fingerprint)) {
    console.warn(JSON.stringify({
      event: 'coordinated_attack_detected',
      cluster: fingerprint.substring(0, 8),
      userId,
      timestamp: new Date().toISOString()
    }));
    return res.status(429).json({ error: 'Rate limit exceeded' });
  }

  // Detect probing patterns
  const analysis = await defense.detectProbingPattern(userId, fingerprint, inputData);

  if (analysis.isAnomalous) {
    // Log security event
    console.error(JSON.stringify({
      event: 'model_inversion_attempt_detected',
      userId,
      anomalyScore: analysis.anomalyScore,
      indicators: analysis.indicators,
      timestamp: new Date().toISOString(),
      action: 'blocking_request'
    }));

    // Block or degrade response
    if (analysis.anomalyScore > 0.9) {
      // High confidence attack - block completely
      await redis.set(`blocked:${userId}`, '1', 'EX', 86400);
      return res.status(403).json({ error: 'Access denied' });
    } else {
      // Medium confidence - return degraded response
      req.degradedResponse = true;
    }
  }

  req.queryFingerprint = fingerprint;
  req.anomalyScore = analysis.anomalyScore;
  next();
}

// Adaptive response based on threat level
function generateAdaptiveResponse(predictions, anomalyScore, degraded) {
  const epsilon = 0.1 + (anomalyScore * 0.4); // More noise for suspicious requests
  const noisyPredictions = predictions.map(p => {
    const noise = (Math.random() - 0.5) * (2 / epsilon);
    return Math.max(0, Math.min(1, p + noise * 0.1));
  });

  if (degraded) {
    // Return only top prediction with categorical label
    const topIdx = noisyPredictions.indexOf(Math.max(...noisyPredictions));
    return [{ classIndex: topIdx, confidence: 'detected' }];
  }

  // Normal response - top 3 with bucketed confidence
  const indexed = noisyPredictions.map((p, i) => ({ prob: p, index: i }));
  indexed.sort((a, b) => b.prob - a.prob);

  return indexed.slice(0, 3).map(item => ({
    classIndex: item.index,
    confidence: item.prob > 0.8 ? 'high' : item.prob > 0.5 ? 'medium' : 'low'
  }));
}

app.post('/api/v2/predict',
  modelInversionDetection,
  body('inputData').isArray().isLength({ min: 1, max: 1000 }),
  body('inputData.*').isFloat({ min: -1, max: 1 }),
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ error: 'Invalid input' });
    }

    const requestId = crypto.randomUUID();

    try {
      const inputTensor = tf.tensor2d([req.body.inputData]);
      const prediction = global.model.predict(inputTensor);
      const probabilities = await prediction.array();

      const response = generateAdaptiveResponse(
        probabilities[0],
        req.anomalyScore || 0,
        req.degradedResponse || false
      );

      res.json({ requestId, predictions: response });

      inputTensor.dispose();
      prediction.dispose();
    } catch (error) {
      console.error(`Error [${requestId}]:`, error.message);
      res.status(500).json({ error: 'Prediction failed', requestId });
    }
  }
);

module.exports = app;
